CREATE TABLE `user` (`id` varchar(36) NOT NULL,`name` varchar(160) NOT NULL,`email` varchar(255) NOT NULL,`email_verified` boolean NOT NULL DEFAULT false,`image` text,`two_factor_enabled` boolean NOT NULL DEFAULT false,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `user_id` PRIMARY KEY(`id`),CONSTRAINT `user_email_unique` UNIQUE(`email`));
CREATE TABLE `session` (`id` varchar(36) NOT NULL,`expires_at` datetime NOT NULL,`token` varchar(255) NOT NULL,`ip_address` varchar(64),`user_agent` text,`user_id` varchar(36) NOT NULL,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `session_id` PRIMARY KEY(`id`),CONSTRAINT `session_token_unique` UNIQUE(`token`),CONSTRAINT `session_user_fk` FOREIGN KEY (`user_id`) REFERENCES `user`(`id`) ON DELETE CASCADE,INDEX `session_user_idx` (`user_id`));
CREATE TABLE `account` (`id` varchar(36) NOT NULL,`account_id` varchar(255) NOT NULL,`provider_id` varchar(100) NOT NULL,`user_id` varchar(36) NOT NULL,`access_token` text,`refresh_token` text,`id_token` text,`access_token_expires_at` datetime,`refresh_token_expires_at` datetime,`scope` text,`password` text,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `account_id_pk` PRIMARY KEY(`id`),CONSTRAINT `account_user_fk` FOREIGN KEY (`user_id`) REFERENCES `user`(`id`) ON DELETE CASCADE,INDEX `account_user_idx` (`user_id`));
CREATE TABLE `verification` (`id` varchar(36) NOT NULL,`identifier` varchar(255) NOT NULL,`value` text NOT NULL,`expires_at` datetime NOT NULL,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `verification_id` PRIMARY KEY(`id`),INDEX `verification_identifier_idx` (`identifier`));
CREATE TABLE `two_factor` (`id` varchar(36) NOT NULL,`secret` text NOT NULL,`backup_codes` text NOT NULL,`user_id` varchar(36) NOT NULL,CONSTRAINT `two_factor_id` PRIMARY KEY(`id`),CONSTRAINT `two_factor_user_unique` UNIQUE(`user_id`),CONSTRAINT `two_factor_user_fk` FOREIGN KEY (`user_id`) REFERENCES `user`(`id`) ON DELETE CASCADE);
CREATE TABLE `contact_messages` (`id` varchar(36) NOT NULL,`name` varchar(120) NOT NULL,`email` varchar(255) NOT NULL,`message` text NOT NULL,`status` enum('new','in_progress','replied','archived') NOT NULL DEFAULT 'new',`internal_note` text,`delivery_status` enum('pending','sent','failed') NOT NULL DEFAULT 'pending',`delivery_error` text,`read_at` datetime,`replied_at` datetime,`consent_at` datetime NOT NULL,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `contact_messages_id` PRIMARY KEY(`id`),INDEX `messages_status_created_idx` (`status`,`created_at`));
CREATE TABLE `site_content` (`id` varchar(32) NOT NULL,`content` json NOT NULL,`updated_by` varchar(36),`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `site_content_id` PRIMARY KEY(`id`),CONSTRAINT `content_user_fk` FOREIGN KEY (`updated_by`) REFERENCES `user`(`id`) ON DELETE SET NULL);
CREATE TABLE `analytics_events` (`id` varchar(36) NOT NULL,`event` enum('page_view','cta_click','form_start','form_submit') NOT NULL,`session_id` varchar(64) NOT NULL,`path` varchar(512) NOT NULL,`label` varchar(160),`referrer_host` varchar(255),`source` varchar(120),`medium` varchar(120),`campaign` varchar(160),`device` enum('mobile','tablet','desktop') NOT NULL,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `analytics_events_id` PRIMARY KEY(`id`),INDEX `analytics_created_event_idx` (`created_at`,`event`),INDEX `analytics_session_idx` (`session_id`));
CREATE TABLE `rate_limits` (`key` varchar(128) NOT NULL,`count` int NOT NULL DEFAULT 1,`window_started_at` datetime NOT NULL,CONSTRAINT `rate_limits_key` PRIMARY KEY(`key`));
CREATE TABLE `projects` (`id` varchar(36) NOT NULL,`name` varchar(180) NOT NULL,`client_name` varchar(180) NOT NULL,`client_email` varchar(255),`status` enum('planned','active','paused','completed') NOT NULL DEFAULT 'planned',`progress` int NOT NULL DEFAULT 0,`starts_at` datetime,`due_at` datetime,`internal_note` text,`public_summary` text,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `projects_id` PRIMARY KEY(`id`));
CREATE TABLE `milestones` (`id` varchar(36) NOT NULL,`project_id` varchar(36) NOT NULL,`title` varchar(180) NOT NULL,`description` text,`status` enum('pending','active','done') NOT NULL DEFAULT 'pending',`is_public` boolean NOT NULL DEFAULT true,`position` int NOT NULL DEFAULT 0,`due_at` datetime,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `milestones_id` PRIMARY KEY(`id`),CONSTRAINT `milestones_project_fk` FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON DELETE CASCADE,INDEX `milestone_project_position_idx` (`project_id`,`position`));
CREATE TABLE `tasks` (`id` varchar(36) NOT NULL,`project_id` varchar(36) NOT NULL,`milestone_id` varchar(36),`title` varchar(180) NOT NULL,`description` text,`column` enum('todo','doing','review','done') NOT NULL DEFAULT 'todo',`is_public` boolean NOT NULL DEFAULT false,`position` int NOT NULL DEFAULT 0,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `tasks_id` PRIMARY KEY(`id`),CONSTRAINT `tasks_project_fk` FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON DELETE CASCADE,CONSTRAINT `tasks_milestone_fk` FOREIGN KEY (`milestone_id`) REFERENCES `milestones`(`id`) ON DELETE SET NULL,INDEX `task_project_column_position_idx` (`project_id`,`column`,`position`));
CREATE TABLE `project_shares` (`id` varchar(36) NOT NULL,`project_id` varchar(36) NOT NULL,`token_hash` varchar(64) NOT NULL,`enabled` boolean NOT NULL DEFAULT true,`expires_at` datetime,`created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT `project_shares_id` PRIMARY KEY(`id`),CONSTRAINT `share_token_unique` UNIQUE(`token_hash`),CONSTRAINT `shares_project_fk` FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON DELETE CASCADE,INDEX `share_project_idx` (`project_id`));
